export class DialogOverlayRef {
    componentRef;
    dialogEl;
    teardownFn;
    constructor(componentRef, dialogEl, teardownFn) {
        this.componentRef = componentRef;
        this.dialogEl = dialogEl;
        this.teardownFn = teardownFn;
    }
    close() {
        this.teardownFn();
    }
    get nativeElement() {
        return this.dialogEl;
    }
}
